import{_ as t,o as e,c as d,ag as o}from"./chunks/framework.CMYkYJvz.js";const b=JSON.parse('{"title":"匹配模式","description":"域名、路径、通配符与正则等匹配模式说明。","frontmatter":{"title":"匹配模式","description":"域名、路径、通配符与正则等匹配模式说明。","editLink":false},"headers":[],"relativePath":"reference/patterns.md","filePath":"reference/patterns.md"}'),s={name:"reference/patterns.md"};function c(n,a,p,i,l,r){return e(),d("div",null,[...a[0]||(a[0]=[o(`<blockquote><p>此页面由 <code>docs/pattern.md</code> 自动同步生成。</p></blockquote><h1 id="匹配器" tabindex="-1">匹配器 <a class="header-anchor" href="#匹配器" aria-label="Permalink to &quot;匹配器&quot;">​</a></h1><p><code>pattern</code> 是 Bifrost 规则中的第一部分，用于匹配请求 URL。</p><h2 id="pattern-类型" tabindex="-1">Pattern 类型 <a class="header-anchor" href="#pattern-类型" aria-label="Permalink to &quot;Pattern 类型&quot;">​</a></h2><p>Bifrost 支持五种 Pattern 类型，系统会按以下顺序自动检测：</p><table tabindex="0"><thead><tr><th>类型</th><th>触发条件</th><th>优先级范围</th></tr></thead><tbody><tr><td>Regex</td><td>以 <code>/</code> 开头且以 <code>/</code>、<code>/i</code>、<code>/u</code>、<code>/iu</code> 结尾</td><td>80</td></tr><tr><td>PathWildcard</td><td>以 <code>^</code> 开头</td><td>60-70</td></tr><tr><td>IP</td><td>符合 IPv4/IPv6/CIDR 格式</td><td>70-95</td></tr><tr><td>Wildcard</td><td>包含 <code>*</code>、<code>?</code> 或以 <code>$</code> 开头</td><td>40-60</td></tr><tr><td>Domain</td><td>默认类型</td><td>100-133+</td></tr></tbody></table><p>所有类型均支持 <code>!</code> 前缀表示否定匹配。</p><h2 id="domain-匹配" tabindex="-1">Domain 匹配 <a class="header-anchor" href="#domain-匹配" aria-label="Permalink to &quot;Domain 匹配&quot;">​</a></h2><p>精确匹配域名、端口和路径。</p><h3 id="格式" tabindex="-1">格式 <a class="header-anchor" href="#格式" aria-label="Permalink to &quot;格式&quot;">​</a></h3><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[protocol://]domain[:port][/path]</span></span></code></pre></div><h3 id="协议匹配" tabindex="-1">协议匹配 <a class="header-anchor" href="#协议匹配" aria-label="Permalink to &quot;协议匹配&quot;">​</a></h3><table tabindex="0"><thead><tr><th>格式</th><th>说明</th></tr></thead><tbody><tr><td><code>http://</code></td><td>仅匹配 HTTP</td></tr><tr><td><code>https://</code></td><td>仅匹配 HTTPS</td></tr><tr><td><code>ws://</code></td><td>仅匹配 WebSocket</td></tr><tr><td><code>wss://</code></td><td>仅匹配 WSS</td></tr><tr><td><code>tunnel://</code></td><td>仅匹配隧道代理</td></tr><tr><td><code>http*://</code></td><td>匹配 HTTP 和 HTTPS</td></tr><tr><td><code>ws*://</code></td><td>匹配 WS 和 WSS</td></tr><tr><td><code>//</code></td><td>匹配所有协议</td></tr><tr><td>无协议</td><td>匹配所有协议</td></tr></tbody></table><h3 id="端口通配符" tabindex="-1">端口通配符 <a class="header-anchor" href="#端口通配符" aria-label="Permalink to &quot;端口通配符&quot;">​</a></h3><table tabindex="0"><thead><tr><th>格式</th><th>示例</th><th>说明</th></tr></thead><tbody><tr><td><code>*</code></td><td><code>example.com:*</code></td><td>匹配任意端口（必须有端口）</td></tr><tr><td><code>8*</code></td><td><code>example.com:8*</code></td><td>匹配以 8 开头的端口</td></tr><tr><td><code>*80</code></td><td><code>example.com:*80</code></td><td>匹配以 80 结尾的端口</td></tr><tr><td><code>8*8</code></td><td><code>example.com:8*8</code></td><td>匹配 88、808、8008 等</td></tr></tbody></table><h3 id="路径匹配" tabindex="-1">路径匹配 <a class="header-anchor" href="#路径匹配" aria-label="Permalink to &quot;路径匹配&quot;">​</a></h3><table tabindex="0"><thead><tr><th>格式</th><th>说明</th></tr></thead><tbody><tr><td><code>/path</code></td><td>匹配该路径及其子路径</td></tr><tr><td><code>/path/*</code></td><td>匹配该路径前缀</td></tr></tbody></table><p><strong>示例</strong>：</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>example.com/api              # 匹配 /api、/api/users、/api?q=1</span></span>
<span class="line"><span>example.com/api/*            # 匹配 /api/ 开头的所有路径</span></span>
<span class="line"><span>https://example.com:8443/api # 完整匹配</span></span></code></pre></div><blockquote><p>ℹ️ 含 <code>*</code> 的 <code>example.com/api/*</code> 在类型检测时会被归类为 <strong>Wildcard</strong>（优先级约 60），而非 Domain。只有裸 <code>/path</code> 前缀形式（如 <code>example.com/api</code>）才保持为 Domain 模式。这里仅描述其运行时匹配行为（命中 <code>/api/users</code>、<code>/api/</code>，但不命中裸 <code>/api</code>）。</p></blockquote><h2 id="ip-匹配" tabindex="-1">IP 匹配 <a class="header-anchor" href="#ip-匹配" aria-label="Permalink to &quot;IP 匹配&quot;">​</a></h2><p>匹配 IP 地址或 CIDR 网段。</p><table tabindex="0"><thead><tr><th>格式</th><th>示例</th><th>说明</th></tr></thead><tbody><tr><td>IPv4</td><td><code>192.168.1.1</code></td><td>精确 IP</td></tr><tr><td>IPv6</td><td><code>::1</code>、<code>2001:db8::1</code></td><td>精确 IP</td></tr><tr><td>CIDR</td><td><code>192.168.0.0/16</code>、<code>10.0.0.0/8</code></td><td>网段匹配</td></tr></tbody></table><h2 id="wildcard-匹配" tabindex="-1">Wildcard 匹配 <a class="header-anchor" href="#wildcard-匹配" aria-label="Permalink to &quot;Wildcard 匹配&quot;">​</a></h2><p>域名通配符匹配，自动识别包含 <code>*</code>、<code>?</code> 或以 <code>$</code> 开头的 pattern。</p><h3 id="通配符" tabindex="-1">通配符 <a class="header-anchor" href="#通配符" aria-label="Permalink to &quot;通配符&quot;">​</a></h3><table tabindex="0"><thead><tr><th>通配符</th><th>说明</th><th>示例</th></tr></thead><tbody><tr><td><code>*</code></td><td>匹配单级（不含 <code>.</code>）</td><td><code>*.example.com</code> 匹配 <code>www.example.com</code>，不匹配 <code>a.b.example.com</code></td></tr><tr><td><code>**</code></td><td>匹配多级（含 <code>.</code>）</td><td><code>**.example.com</code> 匹配 <code>a.b.c.example.com</code></td></tr><tr><td><code>?</code></td><td>匹配单个字符</td><td><code>example?.com</code> 匹配 <code>example1.com</code></td></tr><tr><td><code>$</code></td><td>域名通配符前缀</td><td><code>$example.com</code> 匹配 <code>http(s)://example.com</code> 及其路径</td></tr></tbody></table><h3 id="示例" tabindex="-1">示例 <a class="header-anchor" href="#示例" aria-label="Permalink to &quot;示例&quot;">​</a></h3><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>*.example.com                # 单级子域名</span></span>
<span class="line"><span>**.example.com               # 多级子域名</span></span>
<span class="line"><span>*example*                    # 包含 example</span></span>
<span class="line"><span>example.*/api/*              # 域名后缀 + 路径</span></span>
<span class="line"><span>$*.example.com               # 域名通配符，匹配单级子域名的所有路径</span></span>
<span class="line"><span>$**.example.com              # 域名通配符，匹配多级子域名的所有路径</span></span></code></pre></div><blockquote><p>⚠️ <strong>不要在 Wildcard 模式前加协议前缀</strong>。协议前缀（<code>http://</code>、<code>https://</code>、<code>http*://</code>、<code>ws*://</code>、<code>//</code>）只对 Domain 和 PathWildcard（<code>^</code> 前缀）模式可靠；与 Wildcard 模式组合会出现以下错误行为：</p><table tabindex="0"><thead><tr><th>写法</th><th>实际行为</th></tr></thead><tbody><tr><td><code>*.example.com</code>（裸写，推荐）</td><td>正确匹配单级子域名（HTTP + HTTPS）</td></tr><tr><td><code>http://*.example.com</code> / <code>https://*.example.com</code></td><td>能匹配，但单星 <code>*</code> 会跨越 <code>.</code>，等价于 <code>**</code>（丢失单级限制）</td></tr><tr><td><code>http*://*.example.com</code> / <code>ws*://*.example.com</code></td><td><strong>永不匹配</strong>（静默失效）</td></tr><tr><td><code>//*.example.com</code></td><td><strong>匹配所有 host</strong>（过度匹配，等价于无差别命中，存在误伤风险）</td></tr></tbody></table><p>需要按协议限定时：裸 Wildcard 已覆盖 HTTP/HTTPS；要限定单一协议或匹配 WS/WSS，请改用 Domain 模式（如 <code>http*://api.example.com</code>）或 PathWildcard（如 <code>^http*://example.com/api/*</code>）。</p></blockquote><h2 id="pathwildcard-匹配-前缀" tabindex="-1">PathWildcard 匹配（<code>^</code> 前缀） <a class="header-anchor" href="#pathwildcard-匹配-前缀" aria-label="Permalink to &quot;PathWildcard 匹配（\`^\` 前缀）&quot;">​</a></h2><p>路径通配符匹配，以 <code>^</code> 开头显式声明。支持三种级别的通配符：</p><table tabindex="0"><thead><tr><th>通配符</th><th>正则等价</th><th>说明</th></tr></thead><tbody><tr><td><code>*</code></td><td><code>[^?/]*</code></td><td>单级路径（不含 <code>/</code> 和 <code>?</code>）</td></tr><tr><td><code>**</code></td><td><code>[^?]*</code></td><td>多级路径（不含 <code>?</code>）</td></tr><tr><td><code>***</code></td><td><code>.*</code></td><td>任意字符（含 <code>/</code> 和 <code>?</code>）</td></tr></tbody></table><h3 id="示例-1" tabindex="-1">示例 <a class="header-anchor" href="#示例-1" aria-label="Permalink to &quot;示例&quot;">​</a></h3><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>^example.com/api/*/info      # 匹配 /api/users/info，不匹配 /api/a/b/info</span></span>
<span class="line"><span>^example.com/api/**          # 匹配 /api/a/b/c，不匹配 /api/a?q=1</span></span>
<span class="line"><span>^example.com/api/***         # 匹配任意内容，包括 /api/a/b?q=1</span></span></code></pre></div><h2 id="regex-匹配" tabindex="-1">Regex 匹配 <a class="header-anchor" href="#regex-匹配" aria-label="Permalink to &quot;Regex 匹配&quot;">​</a></h2><p>正则表达式匹配，语法与 JavaScript 正则兼容。</p><h3 id="格式-1" tabindex="-1">格式 <a class="header-anchor" href="#格式-1" aria-label="Permalink to &quot;格式&quot;">​</a></h3><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/pattern/[flags]</span></span></code></pre></div><h3 id="flags" tabindex="-1">Flags <a class="header-anchor" href="#flags" aria-label="Permalink to &quot;Flags&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Flag</th><th>说明</th></tr></thead><tbody><tr><td><code>i</code></td><td>大小写不敏感</td></tr><tr><td><code>u</code></td><td>Unicode 模式</td></tr></tbody></table><h3 id="示例-2" tabindex="-1">示例 <a class="header-anchor" href="#示例-2" aria-label="Permalink to &quot;示例&quot;">​</a></h3><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/\\.example\\.com/             # 匹配 .example.com</span></span>
<span class="line"><span>/api\\/v\\d+/i                 # 大小写不敏感匹配</span></span>
<span class="line"><span>/测试/u                      # Unicode 匹配</span></span></code></pre></div><h2 id="否定匹配" tabindex="-1">否定匹配 <a class="header-anchor" href="#否定匹配" aria-label="Permalink to &quot;否定匹配&quot;">​</a></h2><p>所有类型均支持 <code>!</code> 前缀表示否定：</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>!example.com                 # 排除 example.com</span></span>
<span class="line"><span>!192.168.0.0/16              # 排除内网 IP</span></span>
<span class="line"><span>!*.internal.com              # 排除 internal.com 子域名</span></span>
<span class="line"><span>!/\\.test\\./                  # 排除包含 .test. 的 URL</span></span></code></pre></div><h2 id="子匹配传值" tabindex="-1">子匹配传值 <a class="header-anchor" href="#子匹配传值" aria-label="Permalink to &quot;子匹配传值&quot;">​</a></h2><p>Wildcard、PathWildcard 和 Regex 支持捕获组，通过 <code>$1</code>-<code>$9</code> 引用：</p><h3 id="wildcard-传值" tabindex="-1">Wildcard 传值 <a class="header-anchor" href="#wildcard-传值" aria-label="Permalink to &quot;Wildcard 传值&quot;">​</a></h3><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>*.example.com file:///data/$1        # $1 = 子域名</span></span>
<span class="line"><span>example.*/api/* file:///mock/$1/$2   # $1 = TLD, $2 = 路径</span></span></code></pre></div><h3 id="pathwildcard-传值" tabindex="-1">PathWildcard 传值 <a class="header-anchor" href="#pathwildcard-传值" aria-label="Permalink to &quot;PathWildcard 传值&quot;">​</a></h3><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>^example.com/api/*/info file:///mock/$1.json   # $1 = 单级路径</span></span>
<span class="line"><span>^example.com/*/*       file:///data/$1/$2      # $1, $2 = 各级路径</span></span></code></pre></div><h3 id="regex-传值" tabindex="-1">Regex 传值 <a class="header-anchor" href="#regex-传值" aria-label="Permalink to &quot;Regex 传值&quot;">​</a></h3><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/api\\/v(\\d+)\\/users\\/(\\d+)/ reqHeaders://X-Version=$1 reqHeaders://X-ID=$2</span></span></code></pre></div><blockquote><p><code>reqHeaders://</code> 不以 <code>&amp;</code> 拆分多个 header：写成 <code>reqHeaders://X-Version=$1&amp;X-ID=$2</code> 只会设置单个请求头 <code>X-Version: &lt;值&gt;&amp;X-ID=&lt;值&gt;</code>（<code>&amp;X-ID=...</code> 成为值的一部分）。要设置多个 header，请用多个独立的 <code>reqHeaders://</code> 操作（如上例），详见 operation.md。</p></blockquote><h2 id="优先级" tabindex="-1">优先级 <a class="header-anchor" href="#优先级" aria-label="Permalink to &quot;优先级&quot;">​</a></h2><p>规则按优先级从高到低匹配：</p><table tabindex="0"><thead><tr><th>类型</th><th>优先级</th><th>说明</th></tr></thead><tbody><tr><td>Domain（完整）</td><td>≥130</td><td>100 基础 +5 协议 +10 端口 +（15+路径段数）精确路径</td></tr><tr><td>Domain（基础）</td><td>100</td><td>仅域名</td></tr><tr><td>IP（精确）</td><td>95</td><td>单个 IP</td></tr><tr><td>Regex</td><td>80</td><td>正则表达式</td></tr><tr><td>IP（CIDR）</td><td>70-78</td><td>按前缀长度</td></tr><tr><td>PathWildcard</td><td>60-70</td><td><code>*</code> &gt; <code>**</code> &gt; <code>***</code></td></tr><tr><td>Wildcard</td><td>40-60</td><td>按类型</td></tr></tbody></table><h2 id="配置示例" tabindex="-1">配置示例 <a class="header-anchor" href="#配置示例" aria-label="Permalink to &quot;配置示例&quot;">​</a></h2><h3 id="域名匹配" tabindex="-1">域名匹配 <a class="header-anchor" href="#域名匹配" aria-label="Permalink to &quot;域名匹配&quot;">​</a></h3><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>example.com proxy://127.0.0.1:8080</span></span>
<span class="line"><span>http*://api.example.com cache://3600</span></span>
<span class="line"><span>example.com:8*/api/* file:///mock</span></span></code></pre></div><blockquote><p>上例第三行的 <code>example.com:8*/api/*</code> 是裸 Wildcard，不要写成 <code>//example.com:8*/api/*</code>：<code>//</code> 前缀与 Wildcard 组合会匹配所有 host（见上文 Wildcard 协议前缀说明）。</p></blockquote><h3 id="ip-匹配-1" tabindex="-1">IP 匹配 <a class="header-anchor" href="#ip-匹配-1" aria-label="Permalink to &quot;IP 匹配&quot;">​</a></h3><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>192.168.1.1 proxy://127.0.0.1:3000</span></span>
<span class="line"><span>10.0.0.0/8 reqHeaders://X-Matched-Private=1</span></span>
<span class="line"><span>!192.168.0.0/16 proxy://external</span></span></code></pre></div><h3 id="通配符匹配" tabindex="-1">通配符匹配 <a class="header-anchor" href="#通配符匹配" aria-label="Permalink to &quot;通配符匹配&quot;">​</a></h3><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>*.example.com proxy://127.0.0.1:8080</span></span>
<span class="line"><span>**.cdn.example.com cache://86400</span></span>
<span class="line"><span>$api.example.com file:///mock</span></span></code></pre></div><h3 id="路径通配符匹配" tabindex="-1">路径通配符匹配 <a class="header-anchor" href="#路径通配符匹配" aria-label="Permalink to &quot;路径通配符匹配&quot;">​</a></h3><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>^example.com/api/*/info file:///mock/$1.json</span></span>
<span class="line"><span>^example.com/static/** cache://3600</span></span>
<span class="line"><span>^api.example.com/v*/users/*** reqHeaders://X-Api-Pattern=path-wildcard</span></span></code></pre></div><h3 id="正则匹配" tabindex="-1">正则匹配 <a class="header-anchor" href="#正则匹配" aria-label="Permalink to &quot;正则匹配&quot;">​</a></h3><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/^https?:\\/\\/.*\\.example\\.com/ proxy://127.0.0.1:8080</span></span>
<span class="line"><span>/\\/api\\/v(\\d+)\\// reqHeaders://X-Version=$1</span></span>
<span class="line"><span>/\\.(jpg|png|gif)$/i cache://86400</span></span></code></pre></div><h2 id="扩展阅读" tabindex="-1">扩展阅读 <a class="header-anchor" href="#扩展阅读" aria-label="Permalink to &quot;扩展阅读&quot;">​</a></h2><ul><li><a href="./rule-engine">规则语法文档</a>：了解完整的规则语法结构</li><li><a href="./operations">操作指令文档</a>：学习如何配置操作指令</li><li><a href="./rules/">规则协议手册</a>：按协议查看各能力说明与示例</li></ul>`,72)])])}const m=t(s,[["render",c]]);export{b as __pageData,m as default};
